  38→// ── Bundled font setup for Sharp/librsvg SVG text rendering ──
  39→const __filename = fileURLToPath(import.meta.url);
  40→const __dirname = dirname(__filename);
  41→const FONT_DIR = join(__dirname, '.fonts');
  42→const FONT_PATH = join(FONT_DIR, 'DejaVuSans.ttf');
  43→const FONT_BOLD_PATH = join(FONT_DIR, 'DejaVuSans-Bold.ttf');
  44→let fontsReady = false;
  45→
  46→async function ensureShareFonts() {
  47→    if (fontsReady) return;
  48→    try {
  49→        if (!existsSync(FONT_DIR)) mkdirSync(FONT_DIR, { recursive: true });
  50→
  51→        const downloads = [];
  52→        if (!existsSync(FONT_PATH)) {
  53→            downloads.push(
  54→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans.ttf')
  55→                    .then(r => { if (!r.ok) throw new Error(`Font fetch failed: ${r.status}`); return r.arrayBuffer(); })
  56→                    .then(buf => writeFileSync(FONT_PATH, Buffer.from(buf)))
  57→            );
  58→        }
  59→        if (!existsSync(FONT_BOLD_PATH)) {
  60→            downloads.push(
  61→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans-Bold.ttf')
  62→                    .then(r => { if (!r.ok) throw new Error(`Bold font fetch failed: ${r.status}`); return r.arrayBuffer(); })
  63→                    .then(buf => writeFileSync(FONT_BOLD_PATH, Buffer.from(buf)))
  64→            );
  65→        }
  66→        if (downloads.length) await Promise.all(downloads);
  67→
  68→        fontsReady = true;
  69→        console.log('Share fonts ready:', FONT_DIR);
  70→    } catch (err) {
  71→        console.error('Failed to setup share fonts:', err?.message || err);
  72→    }
  73→}
