 152→const canonicalizeMetricsPath = (rawPath = '') => {
 153→    const normalized = normalizeApiPath(rawPath);
 154→    return normalized
 155→        .replace(/\/[0-9a-f]{8}-[0-9a-f-]{27,}(?=\/|$)/ig, '/:id')
 156→        .replace(/\/\d+(?=\/|$)/g, '/:id');
