 173→const classifyStatusBucket = (statusCode) => {
 174→    if (statusCode >= 200 && statusCode < 300) return '2xx';
 175→    if (statusCode >= 300 && statusCode < 400) return '3xx';
 176→    if (statusCode >= 400 && statusCode < 500) return '4xx';
 177→    if (statusCode >= 500 && statusCode < 600) return '5xx';
 178→    return 'other';
 179→};
