 185→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 186→    const normalized = normalizeWhitespace(value);
 187→    if (!normalized) return '';
 188→    if (normalized.length <= maxLength) return normalized;
 189→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 190→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 191→};
