 201→const getRequestOrigin = (req) => {
 202→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 203→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 204→    const host = forwardedHost || req.get('host') || '';
 205→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 206→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 207→        ? forwardedProto
 208→        : requestProtocol === 'http' || requestProtocol === 'https'
 209→            ? requestProtocol
 210→            : 'https';
 211→
 212→    if (!host) {
 213→        return SITE_URL;
 214→    }
 215→
 216→    return `${protocol}://${host}`;
 217→};
