 219→const pickFirstNonEmptyString = (...values) => {
 220→    for (const value of values) {
 221→        if (typeof value === 'string') {
 222→            const trimmed = value.trim();
 223→            if (trimmed) return trimmed;
 224→        }
 225→    }
 226→    return '';
 227→};
