 235→const imageFromNodeLike = (nodeLike) => {
 236→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 237→
 238→    const src = pickFirstNonEmptyString(
 239→        nodeLike.src,
 240→        nodeLike.url,
 241→        nodeLike.image_url,
 242→        nodeLike.imageUrl,
 243→        nodeLike?.payload?.src,
 244→        nodeLike?.data?.src
 245→    );
 246→    if (!src) return null;
 247→
 248→    return {
 249→        src,
 250→        width: parseImageDimension(nodeLike.width),
 251→        height: parseImageDimension(nodeLike.height),
 252→    };
 253→};
