 325→const resolveAbsoluteHttpUrl = (rawUrl) => {
 326→    try {
 327→        const raw = String(rawUrl || '').trim();
 328→        if (!raw) return null;
 329→
 330→        const isSupabasePath =
 331→            raw.startsWith('/storage/v1/object/public/')
 332→            || raw.startsWith('storage/v1/object/public/');
 333→
 334→        const baseUrl = isSupabasePath && SUPABASE_URL
 335→            ? `${SUPABASE_URL}/`
 336→            : SITE_URL;
 337→
 338→        const parsed = new URL(raw, baseUrl);
 339→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 340→            return null;
 341→        }
 342→        return parsed.toString();
 343→    } catch {
 344→        return null;
 345→    }
 346→};
