 379→const isSafeRemoteImageUrl = (imageUrl) => {
 380→    try {
 381→        const parsed = new URL(imageUrl);
 382→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 383→            return false;
 384→        }
 385→
 386→        const hostname = parsed.hostname.toLowerCase();
 387→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
 388→            return false;
 389→        }
 390→
 391→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
 392→            return false;
 393→        }
 394→
 395→        return true;
 396→    } catch {
 397→        return false;
 398→    }
 399→};
