 401→const evaluateShareImageCandidate = (rawUrl) => {
 402→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
 403→    if (!absoluteUrl) {
 404→        return {
 405→            ok: false,
 406→            reason: 'invalid_or_non_http_url',
 407→            resolvedUrl: null,
 408→        };
 409→    }
 410→
 411→    let path = '';
 412→    try {
 413→        const parsed = new URL(absoluteUrl);
 414→        path = String(parsed.pathname || '').toLowerCase();
 415→    } catch {
 416→        return {
 417→            ok: false,
 418→            reason: 'invalid_resolved_url',
 419→            resolvedUrl: null,
 420→        };
 421→    }
 422→
 423→    if (path.endsWith('.svg')) {
 424→        return {
 425→            ok: false,
 426→            reason: 'svg_not_supported_for_share_image',
 427→            resolvedUrl: absoluteUrl,
 428→        };
 429→    }
 430→
 431→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
 432→        return {
 433→            ok: false,
 434→            reason: 'unsafe_remote_url',
 435→            resolvedUrl: absoluteUrl,
 436→        };
 437→    }
 438→
 439→    return {
 440→        ok: true,
 441→        reason: 'ok',
 442→        resolvedUrl: absoluteUrl,
 443→    };
 444→};
