 446→const fetchRemoteImageBuffer = async (imageUrl) => {
 447→    const controller = new AbortController();
 448→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
 449→
 450→    try {
 451→        const response = await fetch(imageUrl, {
 452→            method: 'GET',
 453→            redirect: 'follow',
 454→            signal: controller.signal,
 455→            headers: {
 456→                Accept: 'image/*,*/*;q=0.8',
 457→                'Accept-Encoding': 'identity',
 458→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
 459→            },
 460→        });
 461→
 462→        if (!response.ok) {
 463→            throw new Error(`upstream image status ${response.status}`);
 464→        }
 465→
 466→        const finalUrl = response.url || imageUrl;
 467→        if (!isSafeRemoteImageUrl(finalUrl)) {
 468→            throw new Error('upstream redirected to unsafe url');
 469→        }
 470→
 471→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
 472→        if (!contentType.startsWith('image/')) {
 473→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
 474→        }
 475→        if (contentType.includes('image/svg')) {
 476→            throw new Error('svg images are not used for share previews');
 477→        }
 478→
 479→        const headerContentLength = Number(response.headers.get('content-length'));
 480→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
 481→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 482→        }
 483→
 484→        const arrayBuffer = await response.arrayBuffer();
 485→        const buffer = Buffer.from(arrayBuffer);
 486→
 487→        if (!buffer.length) {
 488→            throw new Error('upstream image is empty');
 489→        }
 490→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
 491→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 492→        }
 493→
 494→        return {
 495→            buffer,
 496→            contentType,
 497→            byteLength: buffer.length,
 498→            finalUrl,
 499→        };
 500→    } finally {
 501→        clearTimeout(timeout);
 502→    }
 503→};
