 505→const convertToOgJpeg = async (inputBuffer) => {
 506→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
 507→        .rotate()
 508→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
