 397→router.get('/getNotifications', requireAuth, async(req, res) =>{
 398→    const {before} = req.query;
 399→    const userId = req.userId;
 400→    const parsedLimit = parseLimitWithinRange(
 401→        req.query.limit,
 402→        NOTIFICATION_LIMIT_MIN,
 403→        NOTIFICATION_LIMIT_MAX,
 404→        NOTIFICATION_DEFAULT_LIMIT
 405→    );
 406→
 407→    if(parsedLimit == null){
 408→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
 409→    }
 410→
 411→    // Fetch a generous amount from both tables, then merge and paginate
 412→    const fetchLimit = parsedLimit + 1;
 413→
 414→    let journalQuery = supabase
 415→    .from('notifications')
 416→    .select(NOTIFICATION_JOURNAL_SELECT)
 417→    .eq('receiver_id', userId)
 418→    .order('created_at', {ascending: false})
 419→    .order('id', {ascending: false})
 420→    .limit(fetchLimit)
 421→
 422→    let opinionQuery = supabase
 423→    .from('notification_opinions')
 424→    .select(NOTIFICATION_OPINION_SELECT)
 425→    .eq('receiver_id', userId)
 426→    .order('created_at', {ascending: false})
 427→    .order('id', {ascending: false})
 428→    .limit(fetchLimit)
 429→
 430→    if(before){
 431→        journalQuery = journalQuery.lt('created_at', before);
 432→        opinionQuery = opinionQuery.lt('created_at', before);
 433→    }
 434→
 435→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 436→
 437→    if(journalResult.error){
 438→        console.error('error while fetching data from notification table:', journalResult.error);
 439→        return res.status(500).json({error: 'error fetching data from notification table'});
 440→    }
 441→    if(opinionResult.error){
 442→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 443→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 444→    }
 445→
 446→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 447→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 448→
 449→    // Merge and sort by created_at descending
 450→    const merged = [...journalNotifs, ...opinionNotifs]
 451→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 452→
 453→    // Likes/bookmarks lookup only for journal notifications
 454→    const journalIds = [...new Set(
 455→        merged
 456→            .filter((n) => n.source === 'journal')
 457→            .map((n) => n.journal_id)
 458→            .filter(Boolean)
 459→    )];
 460→
 461→    let hasLikedResult = [];
 462→    let hasBookMarkedResult = [];
 463→    if(journalIds.length > 0){
 464→        const [hasLiked, hasBookMarked] = await Promise.all([
 465→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 466→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 467→        ]);
 468→
 469→        if(hasLiked.error || hasBookMarked.error){
 470→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 471→        }
 472→        hasLikedResult = hasLiked.data || [];
 473→        hasBookMarkedResult = hasBookMarked.data || [];
 474→    }
 475→
 476→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 477→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 478→
 479→    const formatted = merged.map((notif) => decorateNotificationMedia({
 480→        ...notif,
 481→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 482→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 483→    }))
 484→
 485→    const hasMore = formatted.length > parsedLimit;
 486→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
 487→
 488→    return res.status(200).json(
 489→        {
 490→            hasMore: hasMore,
 491→            data: slicedData,
 492→        }
 493→    )
 494→
 495→})
