313→const resolveMediaUrl = async(bucket, path) => {
314→    const {data: publicUrlData} = supabase.storage
315→        .from(bucket)
316→        .getPublicUrl(path);
317→
318→    const publicUrl = publicUrlData?.publicUrl || null;
319→    if(publicUrl){
320→        return publicUrl;
321→    }
322→
323→    const {data: signedUrlData, error: signedUrlError} = await supabase.storage
324→        .from(bucket)
325→        .createSignedUrl(path, 60 * 60);
326→
327→    if(!signedUrlError && signedUrlData?.signedUrl){
328→        return signedUrlData.signedUrl;
329→    }
330→
331→    return null;
332→};
