32→
33→
34→    try {
35→        const content = JSON.parse(contentString);
36→        const root = content.root;
37→        const children = root?.children || [];
38→            
39→        const parsedData = {
40→            text: [],
41→            slicedText: [],
42→            images: [],
43→            firstImage: null,
44→            wholeText: null,
45→        };
46→        const extractFromNodes = (nodes) =>{
47→            nodes.forEach((node) => {
48→                if(node.type === 'paragraph' || node.type === 'heading'){
49→                    //extract text
50→                    const textNodes = node.children?.filter((child) => child.type === "text") || [];
51→                    const paragraphText = textNodes.map((child) => child.text).join(" "); //join all the array of text into one text form
52→
53→                    if(paragraphText.trim()) parsedData.text.push(paragraphText);
54→
55→                    const imageNodes = node.children?.filter((child) => child.type === 'image') || [];
56→
57→                    imageNodes.forEach((img) => {
58→                        const imageData = {src: img.src, width: img.width, height: img.height};
59→                        parsedData.images.push(imageData)
60→                        if(!parsedData.firstImage) parsedData.firstImage = imageData;
61→                    })
62→                }
63→
64→                if (node.type === "image") {
65→                    const imageData = { src: node.src, width: node.width, height: node.height };
66→                    parsedData.images.push(imageData);
67→                    if (!parsedData.firstImage) parsedData.firstImage = imageData;
68→                 }
69→
70→                if(node.children) extractFromNodes(node.children);
71→            });
72→        }
73→
74→        extractFromNodes(children);
75→
76→        const combinedText = parsedData.text.join(' ').trim();
77→        parsedData.wholeText = combinedText;
78→        parsedData.slicedText = combinedText.length > 215 ? `${combinedText.substring(0, 215)}...` : combinedText;
79→        
80→        return parsedData; //return the parsedData
81→        } catch (error) {
82→            console.error('Error parsing content:', error);
83→            return {
84→                text: [],
85→                slicedText: '',
86→                images: [],
87→                firstImage: null,
88→                wholeText: '',
89→            };
90→        }
91→}
