 1→/**
 2→ * Walk a Lexical JSON tree and collect unique mentionUserId values.
 3→ * Returns an array of user ID strings.
 4→ */
 5→export function extractMentionUserIds(contentJson) {
 6→    const ids = new Set();
 7→
 8→    let parsed;
 9→    try {
10→        parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
11→    } catch (err) {
12→        console.error('[mentions] JSON parse failed:', err.message);
13→        return [];
14→    }
15→
16→    if (!parsed) return [];
17→
18→    const root = parsed?.root ?? parsed;
19→    if (!root || typeof root !== 'object') return [];
20→
21→    function walk(node) {
22→        if (!node) return;
23→        if (node.type === 'mention' && node.mentionUserId) {
24→            ids.add(node.mentionUserId);
25→        }
26→        if (Array.isArray(node.children)) {
27→            for (const child of node.children) {
28→                walk(child);
29→            }
30→        }
31→    }
32→
33→    walk(root);
34→    return [...ids];
