  5→const sitemapRouter = express.Router();
  6→
  7→const CACHE_MAX_AGE_SECONDS = 3600; // 1 hour
  8→const SITEMAP_PAGE_SIZE = 10000; // 10K URLs per sitemap file (protocol max is 50K)
  9→
 10→const escXml = (str) => String(str)
 11→    .replace(/&/g, '&amp;')
 12→    .replace(/</g, '&lt;')
 13→    .replace(/>/g, '&gt;')
 14→    .replace(/"/g, '&quot;')
 15→    .replace(/'/g, '&apos;');
 16→
 17→// ── GET /api/sitemap-posts-:page.xml ── (paginated)
 18→sitemapRouter.get('/sitemap-posts-:page.xml', async (req, res) => {
 19→    try {
 20→        const page = Math.max(1, parseInt(req.params.page, 10) || 1);
 21→        const from = (page - 1) * SITEMAP_PAGE_SIZE;
 22→        const to = from + SITEMAP_PAGE_SIZE - 1;
 23→
 24→        const { data: posts, error } = await supabase
 25→            .from('journals')
 26→            .select('id, title, created_at')
 27→            .eq('privacy', 'public')
 28→            .order('created_at', { ascending: false })
 29→            .range(from, to);
 30→
 31→        if (error) {
 32→            console.error('sitemap-posts query error:', error.message);
 33→            return res.status(500).send('internal error');
 34→        }
 35→
 36→        if (!posts || posts.length === 0) {
 37→            return res.status(404).send('not found');
 38→        }
 39→
 40→        const urls = posts.map((post) => {
 41→            const loc = escXml(makePostUrl(post.id, post.title || ''));
 42→            const lastmod = post.created_at
 43→                ? new Date(post.created_at).toISOString().split('T')[0]
 44→                : '';
 45→            return `  <url>\n    <loc>${loc}</loc>${lastmod ? `\n    <lastmod>${lastmod}</lastmod>` : ''}\n    <changefreq>monthly</changefreq>\n    <priority>0.7</priority>\n  </url>`;
 46→        });
 47→
 48→        const xml = `<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${urls.join('\n')}\n</urlset>`;
 49→
 50→        res.set('Content-Type', 'application/xml; charset=utf-8');
 51→        res.set('Cache-Control', `public, max-age=${CACHE_MAX_AGE_SECONDS}`);
 52→        return res.send(xml);
 53→    } catch (err) {
 54→        console.error('sitemap-posts error:', err?.message || err);
 55→        return res.status(500).send('internal error');
 56→    }
 57→});
 58→
 59→// ── GET /api/sitemap-profiles-:page.xml ── (paginated)
 60→sitemapRouter.get('/sitemap-profiles-:page.xml', async (req, res) => {
 61→    try {
 62→        const page = Math.max(1, parseInt(req.params.page, 10) || 1);
 63→        const from = (page - 1) * SITEMAP_PAGE_SIZE;
 64→        const to = from + SITEMAP_PAGE_SIZE - 1;
 65→
 66→        const { data: users, error } = await supabase
 67→            .from('users')
 68→            .select('id, username')
 69→            .not('username', 'is', null)
 70→            .range(from, to);
 71→
 72→        if (error) {
 73→            console.error('sitemap-profiles query error:', error.message);
 74→            return res.status(500).send('internal error');
 75→        }
 76→
 77→        if (!users || users.length === 0) {
 78→            return res.status(404).send('not found');
 79→        }
 80→
 81→        const urls = users.map((user) => {
 82→            const loc = escXml(`${SITE_URL}/u/${user.username}`);
 83→            return `  <url>\n    <loc>${loc}</loc>\n    <changefreq>weekly</changefreq>\n    <priority>0.6</priority>\n  </url>`;
 84→        });
 85→
 86→        const xml = `<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${urls.join('\n')}\n</urlset>`;
 87→
 88→        res.set('Content-Type', 'application/xml; charset=utf-8');
 89→        res.set('Cache-Control', `public, max-age=${CACHE_MAX_AGE_SECONDS}`);
 90→        return res.send(xml);
 91→    } catch (err) {
 92→        console.error('sitemap-profiles error:', err?.message || err);
 93→        return res.status(500).send('internal error');
 94→    }
 95→});
 96→
 97→// ── GET /api/sitemap-index.xml ── (dynamic — counts rows to generate page list)
 98→sitemapRouter.get('/sitemap-index.xml', async (_req, res) => {
 99→    try {
100→        const [postsCount, profilesCount] = await Promise.all([
101→            supabase.from('journals').select('id', { count: 'exact', head: true }).eq('privacy', 'public'),
102→            supabase.from('users').select('id', { count: 'exact', head: true }).not('username', 'is', null),
103→        ]);
104→
105→        const totalPosts = postsCount.count || 0;
106→        const totalProfiles = profilesCount.count || 0;
107→
108→        const postPages = Math.max(1, Math.ceil(totalPosts / SITEMAP_PAGE_SIZE));
109→        const profilePages = Math.max(1, Math.ceil(totalProfiles / SITEMAP_PAGE_SIZE));
110→
111→        let sitemaps = `  <sitemap>\n    <loc>${escXml(`${SITE_URL}/sitemap.xml`)}</loc>\n  </sitemap>\n`;
112→
113→        for (let i = 1; i <= postPages; i++) {
114→            sitemaps += `  <sitemap>\n    <loc>${escXml(`${SITE_URL}/api/sitemap-posts-${i}.xml`)}</loc>\n  </sitemap>\n`;
115→        }
116→        for (let i = 1; i <= profilePages; i++) {
117→            sitemaps += `  <sitemap>\n    <loc>${escXml(`${SITE_URL}/api/sitemap-profiles-${i}.xml`)}</loc>\n  </sitemap>\n`;
118→        }
119→
120→        const xml = `<?xml version="1.0" encoding="UTF-8"?>\n<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${sitemaps}</sitemapindex>`;
121→
122→        res.set('Content-Type', 'application/xml; charset=utf-8');
123→        res.set('Cache-Control', `public, max-age=${CACHE_MAX_AGE_SECONDS}`);
124→        return res.send(xml);
125→    } catch (err) {
126→        console.error('sitemap-index error:', err?.message || err);
127→        return res.status(500).send('internal error');
128→    }
129→});
